sql:
SELECT type, COUNT(*)
FROM interventions
GROUP BY type;

SELECT name
FROM interventions
WHERE mixed IS NOT NULL AND mixed != '';

SELECT AVG(budget) AS average_budget
FROM interventions
WHERE cannabis = 'high';

SELECT * 
FROM interventions
WHERE alcohol_use NOT IN ('Low', 'Moderate', 'Medium', 'None');

SELECT * 
FROM intervention_outcomes 
WHERE intervention_id = '0';

SELECT i.intervention_id, s.support_name
FROM interventions i
LEFT JOIN supports s ON i.support = s.support_id;
